vulnerable.code:
// VULNERABLE: writing user input into innerHTML
const userInput = document.getElementById('comment').value;
document.getElementById('preview').innerHTML = userInput;

// If userInput = '<img src=x onerror=alert(1)>'
// The browser renders the img tag and executes the onerror handler

secure.code:
// SECURE: use textContent instead of innerHTML
const userInput = document.getElementById('comment').value;
document.getElementById('preview').textContent = userInput;

// textContent treats the string as plain text — no HTML parsing
// '<img src=x onerror=alert(1)>' is displayed literally as text

